import React, { useEffect, useState } from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Myappointments() {
  const [appointments, setAppointments] = useState([]);

  // ================= POPUP =================
  const [popup, setPopup] = useState({
    show: false,
    message: "",
    type: ""
  });

  const showPopup = (message, type = "error") => {
    setPopup({ show: true, message, type });

    setTimeout(() => {
      setPopup({ show: false, message: "", type: "" });
    }, 2000);
  };

  // ================= FETCH =================
  useEffect(() => {
    fetch("http://127.0.0.1:8000/my-appointments/", {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setAppointments(data);
      })
      .catch(() => {
        showPopup("Failed to load appointments ❌", "error");
      });
  }, []);

  // ================= CANCEL =================
  const handleCancel = async (id) => {
    showPopup("Cancelling appointment...", "success");

    try {
      const res = await fetch(
        `http://127.0.0.1:8000/cancel-appointment/${id}/`,
        {
          method: "POST",
          headers: {
            Authorization: `Token ${localStorage.getItem("token")}`,
          },
        }
      );

      if (res.ok) {
        showPopup("Appointment cancelled successfully ✅", "success");

        setAppointments((prev) =>
          prev.map((a) =>
            a.id === id ? { ...a, status: "cancelled" } : a
          )
        );
      } else {
        showPopup("Cancel failed ❌", "error");
      }
    } catch (error) {
      showPopup("Server error ❌", "error");
    }
  };

  const today = new Date();

  const upcoming = appointments.filter(
    (a) =>
      new Date(a.appointment_date) >= today &&
      a.status !== "cancelled"
  );

  const past = appointments.filter(
    (a) =>
      new Date(a.appointment_date) < today ||
      a.status === "completed" ||
      a.status === "cancelled"
  );

  return (
    <div style={styles.container}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <h3>
              {popup.type === "success"
                ? "Success"
                : "Message"}
            </h3>

            <p style={{ marginTop: "10px", color: "#555" }}>
              {popup.message}
            </p>

            <button style={styles.okBtn} onClick={() => setPopup({ show: false })}>
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.main}>

        <h2>📅 Upcoming Appointments</h2>

        <div style={styles.grid}>
          {upcoming.length > 0 ? (
            upcoming.map((a) => (
              <div key={a.id} style={styles.card}>
                <h3>{a.doctor_name}</h3>
                <p>
                  📅 {a.appointment_date} <br />
                  ⏰ {a.time_slot}
                </p>

                <span style={styles.status}>{a.status}</span>

                {a.status !== "cancelled" && (
                  <button
                    style={styles.cancelButton}
                    onClick={() => handleCancel(a.id)}
                  >
                    Cancel
                  </button>
                )}
              </div>
            ))
          ) : (
            <p>No upcoming appointments</p>
          )}
        </div>

      </div>

      <Footer />
    </div>
  );
}

export default Myappointments;

/* ================= STYLES ================= */
const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
  },

  main: {
    flex: 1,
    padding: "40px",
    textAlign: "center",
  },

  grid: {
    display: "flex",
    flexWrap: "wrap",
    gap: "20px",
    justifyContent: "center",
  },

  card: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
    width: "280px",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },

  status: {
    padding: "5px 10px",
    borderRadius: "20px",
    fontSize: "12px",
    background: "#eafaf1",
    color: "#27ae60",
    display: "inline-block",
    marginTop: "10px",
  },

  cancelButton: {
    marginTop: "10px",
    padding: "8px",
    width: "100%",
    background: "#e74c3c",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },

  /* POPUP */
  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 9999,
  },

  popupCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "10px",
    minWidth: "300px",
    textAlign: "center",
  },

  okBtn: {
    marginTop: "15px",
    padding: "8px 15px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
